// distinctAttributeConstraint compares an attribute value across devices.
// All devices must share the same value. When the set of devices is
// empty, any device that has the attribute can be added. After that,
// only matching devices can be added.
//
type distinctAttributeConstraint struct {
	logger        klog.Logger // Includes name and attribute name, so no need to repeat in log messages.
	requestNames  sets.Set[string]
	attributeName resourceapi.FullyQualifiedName
	features      Features

	allocations []constraintAllocation
}

func (m *distinctAttributeConstraint) add(requestName, subRequestName string, device *draapi.Device, deviceID DeviceID) bool {
	if m.requestNames.Len() > 0 && !m.matches(requestName, subRequestName) {
		// Device not affected by constraint.
		return true
	}

	attribute := lookupAttribute(device, deviceID, m.attributeName)
	if attribute == nil {
		// Doesn't have the attribute.
		m.logger.V(7).Info("Constraint not satisfied, attribute not set")
		return false
	}

	if len(m.allocations) == 0 {
		// The first device can always get picked.
		m.allocations = append(m.allocations, newConstraintAllocation(requestName, subRequestName, deviceID, *attribute))
		m.logger.V(7).Info("First attribute added")
		return true
	}

	if !m.matchesAttribute(*attribute) {
		m.logger.V(7).Info("Constraint not satisfied, has some duplicated attributes")
		return false
	}
	m.allocations = append(m.allocations, newConstraintAllocation(requestName, subRequestName, deviceID, *attribute))
	m.logger.V(7).Info("Constraint satisfied by device", "device", deviceID, "numDevices", len(m.allocations))
	return true

}

func (m *distinctAttributeConstraint) remove(requestName, subRequestName string, device *draapi.Device, deviceID DeviceID) {
	if m.requestNames.Len() > 0 && !m.matches(requestName, subRequestName) {
		// Device not affected by constraint.
		return
	}
	m.allocations = removeConstraintAllocation(m.allocations, requestName, subRequestName, deviceID)
	m.logger.V(7).Info("Device removed from constraint set", "device", deviceID, "numDevices", len(m.allocations))
}

func (m *distinctAttributeConstraint) matches(requestName, subRequestName string) bool {
	if subRequestName == "" {
		return m.requestNames.Has(requestName)
	} else {
		fullSubRequestName := fmt.Sprintf("%s/%s", requestName, subRequestName)
		return m.requestNames.Has(requestName) || m.requestNames.Has(fullSubRequestName)
	}
}

func (m *distinctAttributeConstraint) matchesAttribute(attribute resourceapi.DeviceAttribute) bool {
	if m.features.ListTypeAttributes {
		// Set-based comparison for ListAttributes feature:
		// Check that the new device's attribute set is disjoint from all existing devices.
		// This implements "Pairwise Disjoint" semantics for distinct attributes.
		newSet := attributeAsSet(&attribute)
		if newSet == nil {
			m.logger.V(7).Info("Unknown attribute type")
			return false
		}

		// Check that the new device is disjoint from each existing device
		for i := range m.allocations {
			existingSet := attributeAsSet(&m.allocations[i].attribute)
			if existingSet == nil {
				continue
			}
			if newSet.hasIntersection(existingSet) {
				// New device has common elements with an existing device.
				// This violates the distinct constraint.
				m.logger.V(7).Info("Constraint not satisfied, devices have common elements")
				return false
			}
		}

		// New device is disjoint from all existing devices.
		// The constraint is satisfied.
		m.logger.V(7).Info("Constraint satisfied, new device is disjoint from all existing devices")
		return true
	}

	// Scalar comparison (existing behavior)
	for _, allocation := range m.allocations {
		attr := allocation.attribute
		switch {
		case attribute.StringValue != nil:
			if attr.StringValue != nil && *attribute.StringValue == *attr.StringValue {
				m.logger.V(7).Info("String values duplicated")
				return false
			}
		case attribute.IntValue != nil:
			if attr.IntValue != nil && *attribute.IntValue == *attr.IntValue {
				m.logger.V(7).Info("Int values duplicated")
				return false
			}
		case attribute.BoolValue != nil:
			if attr.BoolValue != nil && *attribute.BoolValue == *attr.BoolValue {
				m.logger.V(7).Info("Bool values duplicated")
				return false
			}
		case attribute.VersionValue != nil:
			// semver 2.0.0 requires that version strings are in their
			// minimal form (in particular, no leading zeros). Therefore a
			// strict "exact equal" check can do a string comparison.
			if attr.VersionValue != nil && *attribute.VersionValue == *attr.VersionValue {
				m.logger.V(7).Info("Version values duplicated")
				return false
			}
		default:
			// Unknown value type, cannot match.
			// This condition should not be reached
			// as the unknown value type should be failed on CEL compile (getAttributeValue).
			m.logger.V(7).Info("Distinct attribute type unknown")
			return false
		}
	}
	// All distinct
	return true
}

// constraintAllocation records enough information to undo an individual
// constraint update, including when several devices belong to one request.
type constraintAllocation struct {
	requestName    string
	subRequestName string
	deviceID       DeviceID
	attribute      resourceapi.DeviceAttribute
}

func newConstraintAllocation(requestName, subRequestName string, deviceID DeviceID, attribute resourceapi.DeviceAttribute) constraintAllocation {
	return constraintAllocation{
		requestName:    requestName,
		subRequestName: subRequestName,
		deviceID:       deviceID,
		attribute:      attribute,
	}
}

func removeConstraintAllocation(allocations []constraintAllocation, requestName, subRequestName string, deviceID DeviceID) []constraintAllocation {
	for i := len(allocations) - 1; i >= 0; i-- {
		allocation := allocations[i]
		if allocation.requestName != requestName || allocation.subRequestName != subRequestName || allocation.deviceID != deviceID {
			continue
		}

		copy(allocations[i:], allocations[i+1:])
		return allocations[:len(allocations)-1]
	}

	return allocations
